const fs = require(''fs'');

// Read the curated list from puzzle-words.txt
const curatedWords = fs.readFileSync(''puzzle-words.txt'', ''utf-8'')
  .trim()
  .split(''\n'')
  .map(w => w.trim())
  .filter(w => w.length > 0);

console.log(''Read'', curatedWords.length, ''words from puzzle-words.txt'');

// Save as the main word list (lowercase to match format)
const wordList = curatedWords.map(w => w.toLowerCase());
fs.writeFileSync(''public/words.json'', JSON.stringify(wordList, null, 2));

console.log(''Saved'', wordList.length, ''words to public/words.json'');
console.log(''First 10:'', wordList.slice(0, 10).join('', ''));
")
